  "sql": "SELECT DISTINCT cf.license_id, cf.publisher as vendor, MAX(cf.event_date) as last_activity_date, SUM(cf.amount_usd) as current_cost, COUNT(DISTINCT cf.user_id) as active_users FROM consumption_facts cf WHERE cf.event_date >= CURRENT_DATE AND cf.event_date <= CURRENT_DATE + INTERVAL '6 months' GROUP BY cf.license_id, cf.publisher ORDER BY cf.event_date ASC"
}
